eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   flashcards: () => (/* binding */ flashcards)\n/* harmony export */ });\nconst flashcards = [\n    // ─── 民事法（民法） ───\n    {\n        id: 1,\n        topic: \"civil\",\n        term: \"善管注意義務\",\n        reading: \"ぜんかんちゅういぎむ\",\n        definition: \"善良な管理者として通常要求される程度の注意をもって事務を処理する義務。委任契約（民法644条）から生じ、取締役・弁護士・受任者等に課される。自己の財産に対するよりも高い注意水準。\",\n        example: \"取締役が会社の業務を行う際に負う注意義務（会社法330条）\"\n    },\n    {\n        id: 2,\n        topic: \"civil\",\n        term: \"表見代理\",\n        reading: \"ひょうけんだいり\",\n        definition: \"代理権がないにもかかわらず、外観上代理権があると信じた善意・無過失の第三者を保護するため、無権代理であっても本人に効果を帰属させる制度。民法109条（代理権授与の表示）・110条（権限外行為）・112条（代理権消滅後）の3類型がある。\",\n        example: \"退職した元社員が会社名で契約した場合、相手方が善意無過失なら会社が責任を負う。\"\n    },\n    {\n        id: 3,\n        topic: \"civil\",\n        term: \"錯誤\",\n        reading: \"さくご\",\n        definition: \"意思表示を行う際に、表意者の認識（意思）と表示の内容が一致していない状態。民法95条により、法律行為の目的及び取引上の社会通念に照らして重要な錯誤があれば取り消せる（2020年改正で無効→取消に変更）。\",\n        example: \"A社の土地と思い購入したがB社の土地だった（目的物の錯誤）。\"\n    },\n    {\n        id: 4,\n        topic: \"civil\",\n        term: \"消滅時効\",\n        reading: \"しょうめつじこう\",\n        definition: \"権利を行使しないまま一定期間が経過すると権利が消滅する制度。2020年改正後の原則：「権利を行使できることを知った時から5年」または「権利を行使できる時から10年」のいずれか早い方。\",\n        example: \"売掛金の消滅時効：取引先が倒産等で請求できないまま5年経過で消滅。\"\n    },\n    {\n        id: 5,\n        topic: \"civil\",\n        term: \"抵当権\",\n        reading: \"ていとうけん\",\n        definition: \"債権の担保として、債務者または第三者が提供した不動産等を占有を移転せずに担保とする約定担保物権（民法369条以下）。抵当権が実行されると競売により換価し、優先的に弁済を受ける。\",\n        example: \"住宅ローンの担保として自宅に抵当権を設定する。\"\n    },\n    {\n        id: 6,\n        topic: \"civil\",\n        term: \"相殺\",\n        reading: \"そうさい\",\n        definition: \"互いに同種の債務を負う当事者の一方が、一方的な意思表示により双方の債務を対当額で消滅させること（民法505条）。自働債権（相殺する側）の弁済期が到来していることが必要。\",\n        example: \"A社がB社に100万円の売掛金、B社がA社に80万円の売掛金を持つ場合、差額20万円のみ請求。\"\n    },\n    {\n        id: 7,\n        topic: \"civil\",\n        term: \"債務不履行\",\n        reading: \"さいむふりこう\",\n        definition: \"債務者が正当な理由なく債務の本旨に従った履行をしないこと（民法415条）。①履行遅滞（弁済期経過後の不履行）②履行不能（履行が不可能になった）③不完全履行（履行したが不完全）の3類型がある。\",\n        example: \"請負業者が工事を期日までに完成させなかった場合（履行遅滞）。\"\n    },\n    // ─── 企業法（会社法） ───\n    {\n        id: 8,\n        topic: \"corporate\",\n        term: \"忠実義務\",\n        reading: \"ちゅうじつぎむ\",\n        definition: \"取締役が法令・定款および株主総会の決議を遵守し、会社のために忠実にその職務を行う義務（会社法355条）。利益相反取引・競業避止義務等の根拠となる。\",\n        example: \"取締役が自己の利益のために会社の事業機会を奪うことは忠実義務違反。\"\n    },\n    {\n        id: 9,\n        topic: \"corporate\",\n        term: \"株主代表訴訟\",\n        reading: \"かぶぬしだいひょうそしょう\",\n        definition: \"会社が取締役等の責任追及を怠っている場合に、株主が会社に代わって取締役等に対して損害賠償訴訟を提起できる制度（会社法847条）。6ヶ月前から引き続き株式を保有していることが要件（公開会社の場合）。\",\n        example: \"取締役の不正行為に対し、会社が責任追及しない場合に株主が訴訟を提起する。\"\n    },\n    {\n        id: 10,\n        topic: \"corporate\",\n        term: \"内部統制システム\",\n        reading: \"ないぶとうせいシステム\",\n        definition: \"会社の業務の適正を確保するために必要な体制（会社法362条4項6号）。大会社の取締役会および指名委員会等設置会社では構築が義務付けられる。リスク管理・コンプライアンス体制等を含む。\",\n        example: \"大会社の取締役会は内部統制システムの基本方針を決定しなければならない。\"\n    },\n    {\n        id: 11,\n        topic: \"corporate\",\n        term: \"会社分割\",\n        reading: \"かいしゃぶんかつ\",\n        definition: \"会社の事業の全部または一部を他の会社に承継させる組織再編行為（会社法757条以下）。①吸収分割（既存会社に承継）と②新設分割（新会社を設立して承継）がある。権利義務の包括承継が認められる。\",\n        example: \"グループ会社再編のため、A社の事業部門をB社（子会社）に分割して承継させる。\"\n    },\n    {\n        id: 12,\n        topic: \"corporate\",\n        term: \"特別決議\",\n        reading: \"とくべつけつぎ\",\n        definition: \"株主総会の重要事項を決議する方法（会社法309条2項）。議決権の過半数を有する株主が出席し（定足数）、出席株主の議決権の3分の2以上の賛成が必要。定款変更・合併・解散等に必要。\",\n        example: \"株式会社の定款変更には株主総会の特別決議が必要である。\"\n    },\n    // ─── 商取引法 ───\n    {\n        id: 13,\n        topic: \"commercial\",\n        term: \"クーリング・オフ\",\n        reading: \"クーリング・オフ\",\n        definition: \"特定の取引において、消費者が一定期間内に無条件で契約を解除できる制度（特定商取引法）。訪問販売・電話勧誘販売は8日間、連鎖販売取引・業務提供誘引販売は20日間。理由不要・書面または電磁的方法で行使。\",\n        example: \"訪問販売で購入した商品を、契約書面受領から8日以内に解除する。\"\n    },\n    {\n        id: 14,\n        topic: \"commercial\",\n        term: \"電子承諾通知の到達主義\",\n        reading: \"でんししょうだくつうちのとうたつしゅぎ\",\n        definition: \"インターネット等を利用した電子承諾通知については、相手方に到達した時点で効力が生じる（電子消費者契約法3条）。民法の隔地者間の契約における発信主義（民法526条）の特例。\",\n        example: \"ネット通販での購入確認メールが相手のサーバーに到達した時点で契約成立。\"\n    },\n    {\n        id: 15,\n        topic: \"commercial\",\n        term: \"割賦販売\",\n        reading: \"かっぷはんばい\",\n        definition: \"商品の代金を分割して支払う販売方法（割賦販売法）。①割賦販売②ローン提携販売③包括信用購入あっせん（クレジットカード）等がある。消費者保護の観点から書面交付義務等が規定される。\",\n        example: \"クレジットカードの分割払いで商品を購入する。\"\n    },\n    // ─── 知的財産法 ───\n    {\n        id: 16,\n        topic: \"ip\",\n        term: \"営業秘密\",\n        reading: \"えいぎょうひみつ\",\n        definition: \"不正競争防止法上の保護対象。①秘密管理性（秘密として管理されている）②有用性（事業活動に有用）③非公知性（公然と知られていない）の3要件を満たす技術上・営業上の情報。\",\n        example: \"社内だけに管理された顧客データベース、製造方法のレシピ等。\"\n    },\n    {\n        id: 17,\n        topic: \"ip\",\n        term: \"職務発明\",\n        reading: \"しょくむはつめい\",\n        definition: \"従業員が職務の範囲内でした発明（特許法35条）。①業務範囲内②現在または過去の職務が条件。特許を受ける権利は原則として発明者（従業員）に帰属するが、使用者は法定通常実施権を有する。契約・就業規則で使用者への原始帰属も可能。\",\n        example: \"研究職の社員が業務中に新製品技術を発明した場合。\"\n    },\n    {\n        id: 18,\n        topic: \"ip\",\n        term: \"著作権の著作者人格権\",\n        reading: \"ちょさくけんのちょさくしゃじんかくけん\",\n        definition: \"著作者の人格的利益を保護する権利で、財産権（著作権）とは別個に存在する（著作権法18条以下）。①公表権②氏名表示権③同一性保持権がある。譲渡できず、著作者の死後も一定程度保護される。\",\n        example: \"著作物を無断で改変したり、著作者名を偽ったりすることは著作者人格権侵害。\"\n    },\n    {\n        id: 19,\n        topic: \"ip\",\n        term: \"特許の新規性\",\n        reading: \"とっきょのしんきせい\",\n        definition: \"特許を受けるための要件のひとつ（特許法29条1項）。出願前に公知・公用・刊行物等に記載されていない発明であること。新規性を喪失すると原則として特許を受けられない（例外：新規性喪失の例外規定）。\",\n        example: \"発明を論文で公表した後に特許出願すると、原則として新規性が失われる。\"\n    },\n    {\n        id: 20,\n        topic: \"ip\",\n        term: \"商標の識別力\",\n        reading: \"しょうひょうのしきべつりょく\",\n        definition: \"商標が自他商品・役務を識別できる力（特別顕著性）。識別力がない標章（普通名称・記述的標章・産地等）は商標登録を受けられない（商標法3条1項）。ただし使用により識別力を獲得した場合は登録可能（同条2項）。\",\n        example: \"「りんご」という言葉をりんごの商標登録はできないが、長年の使用で有名になれば例外あり。\"\n    },\n    // ─── 労働法 ───\n    {\n        id: 21,\n        topic: \"labor\",\n        term: \"解雇権濫用法理\",\n        reading: \"かいこけんらんようほうり\",\n        definition: \"客観的合理的な理由なく社会通念上相当と認められない解雇は権利の濫用として無効とする法理（労働契約法16条）。整理解雇では4要素（経営上の必要性・解雇回避努力・人選の合理性・手続の妥当性）が考慮される。\",\n        example: \"業績不振の整理解雇でも、希望退職募集等の解雇回避努力が不足していると無効になる場合がある。\"\n    },\n    {\n        id: 22,\n        topic: \"labor\",\n        term: \"36協定\",\n        reading: \"さぶろくきょうてい\",\n        definition: \"労働基準法36条に基づき、時間外労働・休日労働を命じるために使用者と過半数労働組合または過半数代表者が締結する労使協定。行政への届出が必要。上限：原則月45時間・年360時間（特別条項で月100時間未満・年720時間以内まで延長可）。\",\n        example: \"繁忙期に残業を命じるには、有効な36協定の締結・届出が必要。\"\n    },\n    {\n        id: 23,\n        topic: \"labor\",\n        term: \"就業規則\",\n        reading: \"しゅうぎょうきそく\",\n        definition: \"使用者が定める労働条件・服務規律に関する規則（労働基準法89条）。常時10人以上の労働者を使用する使用者は作成・届出義務がある。労働者への周知義務あり。最低基準効・契約補充効を持つ。\",\n        example: \"就業規則に規定された始業・終業時刻、休日、賃金規程等。\"\n    },\n    {\n        id: 24,\n        topic: \"labor\",\n        term: \"均等待遇・均衡待遇\",\n        reading: \"きんとうたいぐう・きんこうたいぐう\",\n        definition: \"正規労働者と非正規労働者（パート・有期・派遣）の不合理な待遇差を禁止する原則（パートタイム・有期雇用労働法8条・9条、労働者派遣法）。同一労働同一賃金の考え方に基づく。\",\n        example: \"正社員と同じ職務・責任のパート社員に対し合理的理由なく賞与を支払わないことは問題となり得る。\"\n    },\n    // ─── 経済法 ───\n    {\n        id: 25,\n        topic: \"economic\",\n        term: \"私的独占\",\n        reading: \"してきどくせん\",\n        definition: \"事業者が単独または他の事業者と結合して、他の事業者の事業活動を排除・支配することにより、公共の利益に反して一定の取引分野における競争を実質的に制限すること（独禁法2条5項・3条前段）。\",\n        example: \"市場シェアの大きい企業が競合他社の仕入先との取引を妨害して市場を独占しようとする行為。\"\n    },\n    {\n        id: 26,\n        topic: \"economic\",\n        term: \"不公正な取引方法\",\n        reading: \"ふこうせいなとりひきほうほう\",\n        definition: \"公正な競争を阻害するおそれのある取引方法として独禁法が禁止する行為（独禁法19条・2条9項・一般指定）。不当廉売・差別対価・拘束条件付取引・優越的地位の濫用・取引妨害等を含む。\",\n        example: \"大手小売業者が仕入先に対して、理由なく返品・値引きを強要する（優越的地位の濫用）。\"\n    },\n    {\n        id: 27,\n        topic: \"economic\",\n        term: \"課徴金減免制度（リニエンシー）\",\n        reading: \"かちょうきんげんめんせいど\",\n        definition: \"カルテル等に関与した事業者が違反内容を自主申告した場合に、課徴金が減額・免除される制度（独禁法7条の4以下）。最初の申告者は全額免除。順番・申告のタイミングにより減免率が異なる。\",\n        example: \"カルテルに参加した会社が最初に公正取引委員会に申告した場合、課徴金が全額免除される。\"\n    },\n    // ─── 国際法務 ───\n    {\n        id: 28,\n        topic: \"international\",\n        term: \"仲裁合意\",\n        reading: \"ちゅうさいごうい\",\n        definition: \"当事者間の紛争を仲裁により解決することを合意する条項（仲裁法2条）。仲裁合意があると裁判所は訴えを却下（仲裁法14条）。書面性が要求される。紛争発生前の予防的な条項として国際取引契約に多く含まれる。\",\n        example: \"契約書に「本契約に関する紛争はICCの仲裁規則に従い解決する」と定める条項。\"\n    },\n    {\n        id: 29,\n        topic: \"international\",\n        term: \"ニューヨーク条約\",\n        reading: \"ニューヨークじょうやく\",\n        definition: \"外国仲裁判断の承認及び執行に関する条約（1958年）。締約国で下された仲裁判断を他の締約国が承認・執行することを義務付ける。国際取引における仲裁の有効性を支える基盤。日本も批准。\",\n        example: \"シンガポールで下された仲裁判断を日本の裁判所で執行することができる。\"\n    },\n    {\n        id: 30,\n        topic: \"international\",\n        term: \"準拠法\",\n        reading: \"じゅんきょほう\",\n        definition: \"国際取引における法律関係の成立・効力・解釈等を判断するために適用される特定の国の法。当事者自治の原則により、契約当事者は原則として準拠法を自由に選択できる（法の適用に関する通則法7条）。\",\n        example: \"日米間の取引契約で「本契約の準拠法は日本法とする」と定める。\"\n    },\n    {\n        id: 31,\n        topic: \"civil\",\n        term: \"詐欺・強迫による意思表示\",\n        reading: \"さぎ・きょうはくによるいしひょうじ\",\n        definition: \"詐欺による意思表示は取り消せる（民法96条1項）。強迫による意思表示も取り消せる（民法96条1項）。詐欺では善意無過失の第三者に取消を対抗できないが（同3項）、強迫では第三者にも対抗できる。\",\n        example: \"脅迫されて土地を売却した場合、第三者が転売しても取消を主張できる（強迫）。\"\n    },\n    {\n        id: 32,\n        topic: \"labor\",\n        term: \"労働審判\",\n        reading: \"ろうどうしんぱん\",\n        definition: \"地方裁判所が行う個別労働紛争の迅速な解決手続（労働審判法）。労働審判官（裁判官）1名と労働審判員2名で構成。原則3回以内の期日で審理し、調停または審判が下される。異議申立により訴訟に移行可能。\",\n        example: \"不当解雇された労働者が会社に対して地方裁判所に労働審判を申し立てる。\"\n    },\n    {\n        id: 33,\n        topic: \"corporate\",\n        term: \"取締役の競業避止義務\",\n        reading: \"とりしまりやくのきょうぎょうひしぎむ\",\n        definition: \"取締役は自己または第三者のために会社の事業の部類に属する取引をしようとするときは、取締役会（または株主総会）の承認が必要（会社法356条1項1号・365条）。事後の重要事実の報告義務もある。\",\n        example: \"電機メーカーの取締役が同種の電機製品を販売する別会社を設立・運営する場合。\"\n    },\n    {\n        id: 34,\n        topic: \"ip\",\n        term: \"著作物の隣接権\",\n        reading: \"ちょさくぶつのりんせつけん\",\n        definition: \"著作物を伝達・実演する者（実演家・レコード製作者・放送事業者・有線放送事業者）に認められる権利（著作権法89条以下）。著作権とは別に保護される。実演家の保護期間は実演後70年。\",\n        example: \"歌手（実演家）がCDに録音した歌唱には実演家の著作隣接権がある。\"\n    },\n    {\n        id: 35,\n        topic: \"economic\",\n        term: \"企業結合規制\",\n        reading: \"きぎょうけつごうきせい\",\n        definition: \"合併・株式取得・事業譲受等の企業結合が市場の競争を実質的に制限するおそれがある場合に禁止する規制（独禁法15条以下）。一定規模以上の企業結合は事前に公正取引委員会への届出が必要。\",\n        example: \"大手スーパー2社が合併する場合、公正取引委員会の審査が必要になる。\"\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/flashcards.ts\n");

